import fs from 'fs';
import path from 'path';

import type {
  ExtraDependencies,
  ModuleDescriptorWindows,
  ModuleWindowsConfig,
  PackageRevision,
} from '../../types';

const indent = '  ';

/**
 * Scan for C# module files in the windows/ folder of a package.
 * Looks for files matching *Module.cs that contain a class extending Module.
 */
async function scanForCSharpModules(packagePath: string): Promise<ModuleWindowsConfig[]> {
  const windowsDir = path.join(packagePath, 'windows');
  try {
    const entries = await fs.promises.readdir(windowsDir, { withFileTypes: true, recursive: true });
    const moduleConfigs: ModuleWindowsConfig[] = [];

    for (const entry of entries) {
      if (!entry.isFile() || !entry.name.endsWith('Module.cs')) {
        continue;
      }
      const filePath = path.join(windowsDir, entry.name);
      const content = await fs.promises.readFile(filePath, 'utf8');

      // Match: class SomeModule : Module
      const classMatch = content.match(/class\s+(\w+Module)\s*:\s*Module/);
      if (classMatch) {
        const className = classMatch[1];
        // Try to find namespace
        const nsMatch = content.match(/namespace\s+([\w.]+)/);
        const fullyQualified = nsMatch ? `${nsMatch[1]}.${className}` : className;
        moduleConfigs.push({ name: null, class: fullyQualified });
      }
    }

    return moduleConfigs;
  } catch {
    return [];
  }
}

/** Resolves module search result with additional details required for Windows platform. */
export async function resolveModuleAsync(
  packageName: string,
  revision: PackageRevision
): Promise<ModuleDescriptorWindows | null> {
  const config = revision.config;
  if (!config) {
    return null;
  }

  const windowsConfig = config.getWindowsConfig();
  if (!windowsConfig) {
    return null;
  }

  let modules = config.windowsModules();

  // If no explicit modules defined, scan for C# module files
  if (modules.length === 0) {
    modules = await scanForCSharpModules(revision.path);
  }

  if (modules.length === 0) {
    return null;
  }

  const coreFeatures = config.coreFeatures() ?? [];

  return {
    packageName,
    modules,
    projectPath: config.windowsProjectPath(),
    debugOnly: config.windowsDebugOnly(),
    ...(coreFeatures.length > 0 ? { coreFeatures } : {}),
  };
}

export async function resolveExtraBuildDependenciesAsync(
  _projectNativeRoot: string
): Promise<ExtraDependencies | null> {
  // NuGet dependencies are declared in .csproj directly
  return null;
}

/**
 * Generates C# file that contains all autolinked module classes.
 */
export async function generateModulesProviderAsync(
  modules: ModuleDescriptorWindows[],
  targetPath: string
): Promise<void> {
  const generatedFileContent = generateModulesProviderContent(modules);
  const parentPath = path.dirname(targetPath);
  await fs.promises.mkdir(parentPath, { recursive: true });
  await fs.promises.writeFile(targetPath, generatedFileContent, 'utf8');
}

/**
 * Generates the content for the ExpoModulesProvider.g.cs file.
 */
export function generateModulesProviderContent(modules: ModuleDescriptorWindows[]): string {
  const regularModules = modules.filter((m) => !m.debugOnly);
  const debugOnlyModules = modules.filter((m) => m.debugOnly);

  const regularEntries = ([] as ModuleWindowsConfig[])
    .concat(...regularModules.map((m) => m.modules))
    .filter(Boolean);

  const debugOnlyEntries = ([] as ModuleWindowsConfig[])
    .concat(...debugOnlyModules.map((m) => m.modules))
    .filter(Boolean);

  const regularLines = regularEntries.map(
    (entry) => `${indent.repeat(4)}typeof(${entry.class}),`
  );

  const debugOnlyLines = debugOnlyEntries.map(
    (entry) => `${indent.repeat(4)}typeof(${entry.class}),`
  );

  let arrayBody = '';
  if (regularLines.length > 0) {
    arrayBody += regularLines.join('\n') + '\n';
  }
  if (debugOnlyLines.length > 0) {
    arrayBody += `#if DEBUG\n`;
    arrayBody += debugOnlyLines.join('\n') + '\n';
    arrayBody += `#endif\n`;
  }

  return `// <auto-generated/>
// Automatically generated by expo-modules-autolinking.

using System;
using System.Collections.Generic;

namespace Expo.Modules.Autolinking
{
    public static class ExpoModulesProvider
    {
        public static IReadOnlyList<Type> GetModuleClasses()
        {
            return new Type[]
            {
${arrayBody}            };
        }
    }
}
`;
}
